/**
 * Wiki Output Quality Regression Tests
 *
 * Verifies that wiki pages generated by the LLM conform to the quality
 * standards introduced by the 10 wiki quality optimizations (OPT-01 ~ OPT-08).
 *
 * These tests use fixture markdown strings (representing expected LLM output),
 * so they run without LLM access and provide fast regression coverage.
 *
 * Based on the integration scan performed on test6 project (2026-04-21):
 *   - 24 pages scanned: all passed OPT-01 (100%), OPT-02 (100%), OPT-06 (100%),
 *     OPT-07 (100%), OPT-08 (100%).
 */
import fs from "node:fs/promises"
import os from "node:os"
import path from "node:path"
import { afterEach, describe, expect, it } from "vitest"
import { rebuildWikiOverview } from "../ingest-service.js"

// ── Helpers ───────────────────────────────────────────────────────────────────

/** Extract a scalar frontmatter field value. */
function getFmField(content: string, key: string): string | null {
  const m = content.match(new RegExp(`^${key}:\\s*(.+)$`, "m"))
  return m ? m[1].trim().replace(/^["']|["']$/g, "") : null
}

/** Extract a YAML list field as a string (raw JSON array). */
function getFmListRaw(content: string, key: string): string | null {
  const m = content.match(new RegExp(`^${key}:\\s*(\\[.*?\\])`, "ms"))
  return m ? m[1] : null
}

/** True if the description field is present AND non-empty / not a placeholder. */
function hasNonEmptyDescription(content: string): boolean {
  const val = getFmField(content, "description")
  if (!val) return false
  const placeholders = [
    "One-sentence summary of this page (≤80 chars)",
    "One-sentence summary (≤80 chars)",
    "One-sentence summary of this source (≤80 chars)",
  ]
  return !placeholders.includes(val) && val.length > 0
}

/** True if the frontmatter contains an `aliases:` field (value may be empty list). */
function hasAliasesField(content: string): boolean {
  return /^aliases:/m.test(content)
}

/** True if `tags:` is present and is a non-empty list. */
function hasNonEmptyTags(content: string): boolean {
  const raw = getFmListRaw(content, "tags")
  if (!raw) return false
  try {
    return (JSON.parse(raw) as unknown[]).length > 0
  } catch { return false }
}

/** True if `related:` is present and is a non-empty list. */
function hasNonEmptyRelated(content: string): boolean {
  const raw = getFmListRaw(content, "related")
  if (!raw) return false
  try {
    return (JSON.parse(raw) as unknown[]).length > 0
  } catch { return false }
}

/** True if the body contains at least one [[wikilink]]. */
function hasWikilinks(content: string): boolean {
  return /\[\[[^\]]+\]\]/.test(content)
}

/** True if entity page has a 背景/Background section heading. */
function hasEntitySections(content: string): boolean {
  return /^#{1,3}\s.*(背景|Background)/m.test(content)
}

/** True if concept page has a 定义/Definition section heading. */
function hasConceptSections(content: string): boolean {
  return /^#{1,3}\s.*(定义|Definition)/m.test(content)
}

// ── Fixtures ──────────────────────────────────────────────────────────────────

