/** Missing: description, aliases, tags, related, wikilinks, section headers. */
const NON_COMPLIANT_ENTITY = `---
type: entity
title: 某实体
created: 2026-04-21
updated: 2026-04-21
tags: []
related: []
sources: ["report.pdf"]
---

# 某实体

这是一个缺少必要字段和章节的实体页面，没有背景章节，也没有 wikilinks。
`

/** Missing: description, definition section, non-empty tags. */
const NON_COMPLIANT_CONCEPT = `---
type: concept
title: 某概念
aliases: []
created: 2026-04-21
updated: 2026-04-21
tags: []
related: []
sources: ["report.pdf"]
---

# 某概念

这是一个缺少定义章节的概念页面。
`

// ── OPT-01: description frontmatter 字段 ─────────────────────────────────────

describe("OPT-01: description frontmatter 字段", () => {
  it("合规 entity 页面有非空 description", () => {
    expect(hasNonEmptyDescription(COMPLIANT_ENTITY)).toBe(true)
  })

  it("合规 concept 页面有非空 description", () => {
    expect(hasNonEmptyDescription(COMPLIANT_CONCEPT)).toBe(true)
  })

  it("合规 source 页面有非空 description", () => {
    expect(hasNonEmptyDescription(COMPLIANT_SOURCE)).toBe(true)
  })

  it("缺 description 的页面被正确识别为不合规", () => {
    expect(hasNonEmptyDescription(NON_COMPLIANT_ENTITY)).toBe(false)
  })

  it("description 为占位符字符串时，识别为不合规", () => {
    const placeholder = `---\ntype: entity\ntitle: Foo\ndescription: "One-sentence summary (≤80 chars)"\nsources: []\n---\n# Foo`
    expect(hasNonEmptyDescription(placeholder)).toBe(false)
  })

  it("description 内容不超过 120 字符（合规样本）", () => {
    const val = getFmField(COMPLIANT_ENTITY, "description") ?? ""
    expect(val.length).toBeLessThanOrEqual(120)
  })
})

// ── OPT-02: entity/concept 强制 sections ─────────────────────────────────────

describe("OPT-02: entity/concept 强制 sections", () => {
  it("合规 entity 页面含 背景/Background 章节", () => {
    expect(hasEntitySections(COMPLIANT_ENTITY)).toBe(true)
  })

  it("合规 concept 页面含 定义/Definition 章节", () => {
    expect(hasConceptSections(COMPLIANT_CONCEPT)).toBe(true)
  })

  it("缺少章节的 entity 被正确识别为不合规", () => {
    expect(hasEntitySections(NON_COMPLIANT_ENTITY)).toBe(false)
  })

  it("缺少章节的 concept 被正确识别为不合规", () => {
    expect(hasConceptSections(NON_COMPLIANT_CONCEPT)).toBe(false)
  })

  it("entity 含 在本源中的角色/Role in Source 章节", () => {
    expect(/^#{1,3}\s.*(在本源中的角色|Role in Source)/m.test(COMPLIANT_ENTITY)).toBe(true)
  })

  it("concept 含 意义/Significance 章节", () => {
    expect(/^#{1,3}\s.*(意义|Significance)/m.test(COMPLIANT_CONCEPT)).toBe(true)
  })

  it("concept 含 在本源中的体现/In This Source 章节", () => {
    expect(/^#{1,3}\s.*(在本源中的体现|In This Source)/m.test(COMPLIANT_CONCEPT)).toBe(true)
  })
})

// ── OPT-04: rebuildWikiOverview Key Entities / Key Concepts（整合测试）──────

const tempDirs04: string[] = []

async function makeTempProject04(): Promise<string> {
  const dir = await fs.mkdtemp(path.join(os.tmpdir(), "llm-wiki-quality-"))
  tempDirs04.push(dir)
  await fs.mkdir(path.join(dir, "wiki"), { recursive: true })
  return dir
}

async function writeWikiFile04(projectDir: string, relPath: string, content: string): Promise<void> {
  const full = path.join(projectDir, "wiki", relPath)
  await fs.mkdir(path.dirname(full), { recursive: true })
  await fs.writeFile(full, content, "utf-8")
}

afterEach(async () => {
  await Promise.all(tempDirs04.map((dir) => fs.rm(dir, { recursive: true, force: true })))
  tempDirs04.length = 0
})

describe("OPT-04: rebuildWikiOverview 使用 description 优先 + Key Entities/Concepts", () => {
  it("source 有 description 时，overview 显示 description 内容", async () => {
    const dir = await makeTempProject04()
    await writeWikiFile04(dir, "sources/体检报告.md", COMPLIANT_SOURCE)

    await rebuildWikiOverview(dir)
    const ov = await fs.readFile(path.join(dir, "wiki", "overview.md"), "utf-8")

    expect(ov).toContain("韩松于2024年在珠海奥乐医院完成的年度体检结果")
    expect(ov).not.toContain("本报告记录了")  // body text should NOT appear
  })

  it("overview 包含 ## Key Entities 段落并列出 entity slug", async () => {
    const dir = await makeTempProject04()
    await writeWikiFile04(dir, "sources/报告.md", COMPLIANT_SOURCE)
    await writeWikiFile04(dir, "sources/报告/entities/珠海奥乐医院.md", COMPLIANT_ENTITY)

    await rebuildWikiOverview(dir)
    const ov = await fs.readFile(path.join(dir, "wiki", "overview.md"), "utf-8")

    expect(ov).toContain("## Key Entities")
    expect(ov).toContain("[[珠海奥乐医院]]")
  })

  it("overview 包含 ## Key Concepts 段落并列出 concept slug", async () => {
    const dir = await makeTempProject04()
    await writeWikiFile04(dir, "sources/报告.md", COMPLIANT_SOURCE)
    await writeWikiFile04(dir, "sources/报告/concepts/高尿酸血症.md", COMPLIANT_CONCEPT)

    await rebuildWikiOverview(dir)
    const ov = await fs.readFile(path.join(dir, "wiki", "overview.md"), "utf-8")

    expect(ov).toContain("## Key Concepts")
    expect(ov).toContain("[[高尿酸血症]]")
  })

  it("source 无 description 时，overview 回退到正文首行", async () => {
    const dir = await makeTempProject04()
    await writeWikiFile04(
      dir,
      "sources/无描述.md",
      `---\ntype: source\ntitle: 无描述报告\n---\n这是正文第一行内容。`,
    )

    await rebuildWikiOverview(dir)
    const ov = await fs.readFile(path.join(dir, "wiki", "overview.md"), "utf-8")

    expect(ov).toContain("这是正文第一行内容")
  })
})

// ── OPT-06: tags / related 实际填充 ──────────────────────────────────────────

describe("OPT-06: tags/related 实际填充", () => {
  it("合规 entity 页面 tags 非空", () => {
    expect(hasNonEmptyTags(COMPLIANT_ENTITY)).toBe(true)
  })

  it("合规 concept 页面 tags 非空", () => {
    expect(hasNonEmptyTags(COMPLIANT_CONCEPT)).toBe(true)
  })

  it("合规 entity 页面 related 非空", () => {
    expect(hasNonEmptyRelated(COMPLIANT_ENTITY)).toBe(true)
  })

  it("合规 concept 页面 related 非空", () => {
    expect(hasNonEmptyRelated(COMPLIANT_CONCEPT)).toBe(true)
  })

  it("tags: [] 被正确识别为不合规", () => {
    expect(hasNonEmptyTags(NON_COMPLIANT_ENTITY)).toBe(false)
  })

  it("related: [] 被正确识别为不合规", () => {
    expect(hasNonEmptyRelated(NON_COMPLIANT_ENTITY)).toBe(false)
  })
})

// ── OPT-07: aliases 字段存在 ──────────────────────────────────────────────────

describe("OPT-07: aliases 字段存在", () => {
  it("合规 entity 页面有 aliases 字段", () => {
    expect(hasAliasesField(COMPLIANT_ENTITY)).toBe(true)
  })

  it("合规 concept 页面有 aliases 字段", () => {
    expect(hasAliasesField(COMPLIANT_CONCEPT)).toBe(true)
  })

  it("合规 source 页面有 aliases 字段", () => {
    expect(hasAliasesField(COMPLIANT_SOURCE)).toBe(true)
  })

  it("缺 aliases 的页面被正确识别为不合规", () => {
    expect(hasAliasesField(NON_COMPLIANT_ENTITY)).toBe(false)
  })

  it("aliases 值非空时，应有实际内容", () => {
    const raw = getFmListRaw(COMPLIANT_ENTITY, "aliases") ?? "[]"
    const list = JSON.parse(raw) as string[]
    expect(list.length).toBeGreaterThan(0)
  })
})

// ── OPT-08: wikilinks 使用与有效性 ───────────────────────────────────────────

describe("OPT-08: wikilinks 使用", () => {
  it("合规 entity 页面正文含 wikilink", () => {
    expect(hasWikilinks(COMPLIANT_ENTITY)).toBe(true)
  })

  it("合规 concept 页面正文含 wikilink", () => {
    expect(hasWikilinks(COMPLIANT_CONCEPT)).toBe(true)
  })

  it("合规 source 页面正文含 wikilink", () => {
    expect(hasWikilinks(COMPLIANT_SOURCE)).toBe(true)
  })

  it("缺少 wikilink 的页面被正确识别为不合规", () => {
    expect(hasWikilinks(NON_COMPLIANT_ENTITY)).toBe(false)
  })

  it("entity 中的 wikilink 指向有意义的 slug（非空字符串）", () => {
    const links = [...COMPLIANT_ENTITY.matchAll(/\[\[([^\]|]+)(?:\|[^\]]+)?\]\]/g)].map((m) => m[1])
    expect(links.length).toBeGreaterThan(0)
    links.forEach((slug) => expect(slug.trim().length).toBeGreaterThan(0))
  })

  it("concept 中的 wikilink 指向有意义的 slug", () => {
    const links = [...COMPLIANT_CONCEPT.matchAll(/\[\[([^\]|]+)(?:\|[^\]]+)?\]\]/g)].map((m) => m[1])
    expect(links.length).toBeGreaterThan(0)
    links.forEach((slug) => expect(slug.trim().length).toBeGreaterThan(0))
  })
})

// ── 综合判定函数：一页面是否符合全部 OPT 标准 ───────────────────────────────

describe("综合合规判定", () => {
  function isCompliantPage(content: string, type: "entity" | "concept" | "source"): boolean {
    if (!hasNonEmptyDescription(content)) return false
    if (!hasAliasesField(content)) return false
    if (type === "entity" && !hasEntitySections(content)) return false
    if (type === "concept" && !hasConceptSections(content)) return false
    return true
  }

  it("COMPLIANT_ENTITY 通过全部合规检查", () => {
    expect(isCompliantPage(COMPLIANT_ENTITY, "entity")).toBe(true)
  })

  it("COMPLIANT_CONCEPT 通过全部合规检查", () => {
    expect(isCompliantPage(COMPLIANT_CONCEPT, "concept")).toBe(true)
  })

  it("COMPLIANT_SOURCE 通过全部合规检查", () => {
    expect(isCompliantPage(COMPLIANT_SOURCE, "source")).toBe(true)
  })

  it("NON_COMPLIANT_ENTITY 不通过合规检查", () => {
    expect(isCompliantPage(NON_COMPLIANT_ENTITY, "entity")).toBe(false)
  })

  it("NON_COMPLIANT_CONCEPT 不通过合规检查", () => {
    expect(isCompliantPage(NON_COMPLIANT_CONCEPT, "concept")).toBe(false)
  })
})
